query:
{
  dbInstances(
    where: {
      cloudProvider: { eq: "alibaba" }
      engine: { eq: "mysql" }
      NOT: {
        OR: [
          { engineVersion_MATCHES: "^5\\.7(\\.|$)" }
          { engineVersion_MATCHES: "^8\\.0(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engine
    engineVersion
  }
}
